import React from 'react';
import { Globe, ArrowRight } from 'lucide-react';
import HeroBackground from './hero/HeroBackground';
import DeviceMockups from './hero/DeviceMockups';
import ServiceBar from './hero/ServiceBar';
import StatsBar from './hero/StatsBar';

function HeroSection({ lang, setLang, t, scrollToSection }) {
  const screenshots = {
    laptop: '/images/dashboard-screenshot.png',
    phone: '/images/app-screenshot.png',
    tablet: '/images/tablet-screenshot.png'
  };

  return (
    <section className="relative min-h-screen overflow-hidden">
      <HeroBackground />

      {/* Main content - NO max-width, NO mx-auto */}
      <div className="relative z-10 pt-44 pb-20 w-full">
        <div className="flex flex-col lg:flex-row items-start gap-8">

          {/* Left - Text - sát trái */}
          <div className="w-full lg:w-1/2 pl-6 sm:pl-10 md:pl-16 lg:pl-20 pr-4">
            <p className="text-4xl sm:text-5xl md:text-6xl font-black text-white leading-tight">
              Thiết Kế <span className="text-yellow-400">Web</span> &
            </p>
            <p className="text-4xl sm:text-5xl md:text-6xl font-black text-yellow-400 leading-tight">
              Ứng Dụng
            </p>
            <p className="text-4xl sm:text-5xl md:text-6xl font-black text-white leading-tight mb-6">
              Chuyên Nghiệp
            </p>

            <p className="text-lg text-blue-100/90 mb-8 italic">
              Giải pháp số tối ưu cho doanh nghiệp của bạn.
            </p>

            <div className="flex flex-wrap gap-4">
              <button 
                onClick={() => window.location.href = '/contact'} 
                className="group bg-red-500 hover:bg-red-600 text-white px-8 py-4 rounded-lg font-bold text-lg transition-all flex items-center space-x-2 shadow-xl"
              >
                <span>Nhận Tư Vấn</span>
                <ArrowRight className="w-5 h-5 group-hover:translate-x-1 transition-transform" />
              </button>

              <button 
                onClick={() => scrollToSection('portfolio')} 
                className="border-2 border-white text-white px-8 py-4 rounded-lg font-bold text-lg hover:bg-white/10 transition-all"
              >
                Xem Dự Án
              </button>
            </div>
          </div>

          {/* Right - Mockups */}
          <div className="hidden lg:flex w-1/2 h-[500px] items-center justify-center pr-10">
            <DeviceMockups screenshots={screenshots} />
          </div>
        </div>

        {/* Language switcher */}
        <div className="absolute top-8 right-8">
          <button 
            onClick={() => setLang(lang === 'vi' ? 'en' : 'vi')} 
            className="flex items-center space-x-2 bg-white/10 text-white px-4 py-2 rounded-lg hover:bg-white/20"
          >
            <Globe className="w-5 h-5" />
            <span>{lang === 'vi' ? 'EN' : 'VI'}</span>
          </button>
        </div>
      </div>

      {/* Service bar */}
      <div className="relative z-20 max-w-5xl mx-auto px-4 -mt-10">
        <ServiceBar lang={lang} />
      </div>

      {/* Stats */}
      <div className="relative z-10 max-w-4xl mx-auto px-4 mt-16">
        <StatsBar lang={lang} />
      </div>

      <style>{`
        @keyframes float { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-20px); } }
        .animate-float { animation: float 6s ease-in-out infinite; }
      `}</style>
    </section>
  );
}

export default HeroSection;
